import anthropic

client = anthropic.Anthropic()


def call(prompt: str, max_tokens: int = 300, temperature: float = 0.0) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=temperature,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text.strip()


def find_failures(
    prompt: str, eval_examples: list[dict]
) -> list[dict]:
    """Return examples where the prompt produces the wrong answer."""
    failures = []
    for ex in eval_examples:
        prediction = call(f"{prompt}\n\nInput: {ex['input']}", max_tokens=60)
        if ex["output"].lower() not in prediction.lower():
            failures.append({
                "input": ex["input"],
                "expected": ex["output"],
                "got": prediction[:80],
            })
    return failures


def failure_guided_mutation(prompt: str, failures: list[dict]) -> str:
    """Ask the LLM to edit the prompt to fix the observed failures."""
    failure_block = "\n".join(
        f"  Input: {f['input']}\n  Expected: {f['expected']}\n  Got: {f['got']}"
        for f in failures
    )
    return call(
        f"This instruction produces wrong outputs on these cases:\n{failure_block}\n\n"
        f"Current instruction:\n{prompt}\n\n"
        "Rewrite the instruction to fix these failures. Output ONLY the new instruction.",
        temperature=0.3,
    )


EVAL = [
    {"input": "The package arrived damaged.", "output": "negative"},
    {"input": "Fast shipping, great product!", "output": "positive"},
    {"input": "It does what it says.", "output": "neutral"},
    {"input": "I've been waiting 3 weeks and nothing.", "output": "negative"},
]

prompt = "Classify this."
for step in range(3):
    failures = find_failures(prompt, EVAL)
    print(f"Step {step + 1}: {len(failures)} failure(s)")
    if not failures:
        break
    prompt = failure_guided_mutation(prompt, failures)
    print(f"  New prompt: {prompt[:100]}")

print(f"\nFinal prompt: {prompt}")
